sys_variable_value.value:
(function execute(inputs, outputs) {
const utils = new x_759224_magic_c_0.symbology_utils();
var response = JSON.parse(inputs.response);

if(response.data.length > 0){
    gs.info('[RULING PARSER] data length ' + response.data.length);
    //response.data = JSON.parse(response.data);
    for(rule in response.data){
        gs.info('[RULING PARSER] rule ' + response.data[rule]);
        rule = JSON.parse(rule);
        response.data[rule].comment = utils.convertSymbolsToImages(response.data[rule].comment);
        JSON.stringify(response.data[rule]);
    }
    //response.data = JSON.stringify(response.data);
}

outputs.response = JSON.stringify(response);
})(inputs, outputs);

