sys_variable_value.value:
{
  "object": "list",
  "has_more": false,
  "data": [
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "For example, if X is 3, you may target up to four creature cards: one with mana value 3, one with mana value 2, one with mana value 1, and one with mana value 0."
    },
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "If X is 0 for Agadeem's Awakening, you can target one creature card with mana value 0."
    },
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "If a card in a player's graveyard has {X} in its mana cost, X is considered to be 0 for that card."
    },
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "There is a single triangle icon in the top left corner of the front face. There is a double triangle icon in the top left corner of the back face."
    },
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "To determine whether it is legal to play a modal double-faced card, consider only the characteristics of the face you're playing and ignore the other face's characteristics."
    },
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "If an effect allows you to play a specific modal double-faced card, you may cast it as a spell or play it as a land, as determined by which face you choose to play. If an effect allows you to cast (rather than \"play\") a specific modal double-faced card, you can't play it as a land."
    },
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "If an effect allows you to play a land or cast a spell from among a group of cards, you may play or cast a modal double-faced card with any face that fits the criteria of that effect."
    },
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "The mana value of a modal double-faced card is based on the characteristics of the face that's being considered. On the stack and battlefield, consider whichever face is up. In all other zones, consider only the front face. This is different than how the mana value of a transforming double-faced card is determined."
    },
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "A modal double-faced card can't be transformed or be put onto the battlefield transformed. Ignore any instruction to transform a modal double-faced card or to put one onto the battlefield transformed."
    },
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "If an effect puts a double-faced card onto the battlefield, it enters with its front face up. If that front face can't be put onto the battlefield, it doesn't enter the battlefield."
    },
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "If an effect instructs a player to choose a card name, the name of either face may be chosen. If that effect or a linked ability refers to a spell with the chosen name being cast and/or a land with the chosen name being played, it considers only the chosen name, not the other face's name."
    },
    {
      "object": "ruling",
      "oracle_id": "562d71b9-1646-474e-9293-55da6947a758",
      "source": "wotc",
      "published_at": "2020-09-25",
      "comment": "In the Commander variant, a double-faced card's color identity is determined by the mana costs and mana symbols in the rules text of both faces combined. If either face has a color indicator or basic land type, those are also considered."
    }
  ]
}

